-- Full pre-XTRF legacy supplier invoice load (all 219 suppliers), matched to
-- vendors by accent-insensitive name. Replaces the earlier 10-row partial load.
-- Applied to prod via MCP 2026-06-18.
CREATE EXTENSION IF NOT EXISTS unaccent;
CREATE TABLE IF NOT EXISTS public.legacy_supplier_invoice_summary (
  supplier_name_raw text, supplier_name_norm text, n_invoices int,
  earliest date, latest date, total_cad numeric, currencies text[], pairs text[], vendor_id uuid);
TRUNCATE public.legacy_supplier_invoice_summary;
